  let master = g.master;
  let slaves = g.slaves || [];

  if (!doors[master]) continue;

  let masterBusy = busy(master);
  let slaveBusy = slaves.some(s => busy(s));

  if (masterBusy) {
    for (let s of slaves) desiredLocks[s] = true;
  }

  if (slaveBusy) {
    desiredLocks[master] = true;
  }
}

let lockMsgs = [];
for (let d in desiredLocks) {
  if (!doors[d]) doors[d] = {state:'READY', locked:false, lastUpdate:'-'};

  if (doors[d].locked !== desiredLocks[d]) {
    doors[d].locked = desiredLocks[d];
    lockMsgs.push({
      topic: 'sas/' + d + '/lock',
      payload: desiredLocks[d] ? 'LOCKED' : 'UNLOCKED',
      retain: true
    });
  }
}

